import React from "react";
import { useUploader } from "../MainUploader";
import { Button, Flex, Text } from "../../../../";

const MultipleFileUploader = () => {
    const { onPick, files, removeFile, disabled, limit, placeholder, isClassicUploader } =
        useUploader();

    if (!isClassicUploader) {
        return (
            <Flex w={"full"} gap={2}>
                <Button label={"Upload"} onClick={onPick as any} disabled={disabled} />
                <Button
                    label={`${files.length}/${limit} Files Selected`}
                    outlined
                    disabled
                />
            </Flex>
        );
    }

    return (
        <Flex w={"full"} gap={2}>
            {files.map((f, idx) => (
                <Flex
                    key={`${f.name}-${idx}`}
                    flexDirection={"row"}
                    justifyContent={"space-between"}
                    alignItems={"center"}
                    gap={2}
                >
                    <Text as={"span"} textOverflow={"ellipsis"} whiteSpace={"nowrap"}>
                        {f.shortName}
                    </Text>
                    <Button
                        icon="pi pi-times"
                        size={'md'}
                        w={20}
                        severity={"danger"}
                        onClick={removeFile(idx)}
                        disabled={disabled}
                    />
                </Flex>
            ))}

            <Button
                label={placeholder ?? "Tap to add files"}
                onClick={onPick as any}
                disabled={disabled || files.length >= limit}
            />
        </Flex>
    );
};

export default MultipleFileUploader;
